import time

from django.conf import settings
from django.http import HttpResponseForbidden
from django.utils.deprecation import MiddlewareMixin


class RateLimitMiddleware(MiddlewareMixin):
    """
    Rate-limit incoming HTTP requests by client IP address.

    When a client exceeds RATE_LIMIT_REQUESTS requests within RATE_LIMIT_WINDOW
    seconds, further requests are rejected with a 403 Forbidden response.
    """

    # Shared across all instances; keyed by IP, value is list of timestamps.
    _request_log = {}
    _total_requests = 0

    def process_request(self, request):
        max_requests = getattr(settings, "RATE_LIMIT_REQUESTS", 100)
        window = getattr(settings, "RATE_LIMIT_WINDOW", 3600)

        ip = request.META.get("REMOTE_ADDR", "")
        now = time.time()

        RateLimitMiddleware._total_requests += 1
        if RateLimitMiddleware._total_requests % 100 == 0:
            self._cleanup(now, window)

        timestamps = RateLimitMiddleware._request_log.get(ip, [])
        timestamps = [t for t in timestamps if now - t < window]

        if len(timestamps) >= max_requests:
            return HttpResponseForbidden(
                f"Rate limit exceeded for IP {ip}"
            )

        timestamps.append(now)
        RateLimitMiddleware._request_log[ip] = timestamps

    def _cleanup(self, now, window):
        cutoff = now - window
        RateLimitMiddleware._request_log = {
            ip: [t for t in timestamps if t > cutoff]
            for ip, timestamps in RateLimitMiddleware._request_log.items()
            if any(t > cutoff for t in timestamps)
        }
